// Function to prevent common debugging shortcuts
function blockDebuggingShortcuts(event) {
    if (
        event.key === "F12" ||
        (event.ctrlKey && event.key === "U") || // Ctrl + U
        (event.ctrlKey && event.shiftKey && (event.key === "I" || event.key === "C" || event.key === "J")) || // Ctrl+Shift+I/C/J
        (event.metaKey && event.altKey && (event.key === "I" || event.key === "C")) || // Cmd+Option+I/C
        (event.ctrlKey && event.shiftKey && event.key === "X") // Ctrl+Shift+X
    ) {
        // Prevent the default action for the detected key combinations
        event.preventDefault();
        return false;
    }
}

// Set up keydown listener to block developer tools shortcuts
document.addEventListener("keydown", blockDebuggingShortcuts);

