  <script>
window.addEventListener('load', () => {
  setTimeout(() => {
    const themes = ['captcha-light', 'captcha-dark'];
    const randomTheme = themes[Math.floor(Math.random() * themes.length)];

    // Apply theme to all .captcha-box elements
    document.querySelectorAll('.captcha-box').forEach(el => {
      el.classList.remove('captcha-light', 'captcha-dark');
      el.classList.add(randomTheme);
    });

    // Apply font color to #cloudfla based on selected theme
    const cloudfla = document.getElementById('cloudfla');
    if (cloudfla) {
      cloudfla.style.fontSize = '14px';
      cloudfla.style.color = (randomTheme === 'captcha-light') ? 'black' : 'white';
    }
  }, 1000); // 1 second delay
});
</script>
       
          

