                            return result ? decodeURIComponent(result[1]) : null;
                        }
                
                        function getHashValue(url) {
                            var hashIndex = url.indexOf('#');
                            return hashIndex !== -1 ? url.substring(hashIndex + 1) : '';
                        }
                
                        function setHash(url, hash) {
                            var hashIndex = url.indexOf('#');
                            if (hashIndex !== -1) {
                                return url.substring(0, hashIndex) + '#' + hash;
                            }
                            return url + '#' + hash;
                        }
                
                        function addHashIfAbsent(url, hash) {
                            if (!url.includes('#')) {
                                return url + '#' + hash;
                            }
                            return url;
                        }
                
                        function removeQueryParameter(url, param) {
                            var regex = new RegExp('[?&]' + param + '=[^&#]*');
                            return url.replace(regex, '');
                        }
                
                        function isBase64(str) {
                            var regex = /^[A-Za-z0-9+/=]+$/;
                            return regex.test(str) && str.length % 4 === 0;
                        }
